#include <stdio.h>
int main(){
    int t;
    if(scanf("%d",&t)!=1) return 0;
    while(t--){
        int N;
        scanf("%d",&N);
        int F;
        scanf("%d",&F);
        long long sum_unprinted=0;
        for(int i=0;i<F;i++){ int x;
            scanf("%d",&x);
            sum_unprinted+=x;
        }
        int T;
        scanf("%d",&T);
        long long total = (long long)N*(N+1)/2;
        long long printed = total - sum_unprinted;
        double L = N/2.0;
        double expected = printed * (1.0 - T/L);
        printf("%.4f\n", expected);
    }
    return 0;
}

