const lines = require('fs').readFileSync(0,'utf-8').trim().split('\n');
let i=0;
const t = parseInt(lines[i++]);
let results = [];
for(let caseNum=0; caseNum<t; caseNum++) {
  const N = parseInt(lines[i++]);
  const F = parseInt(lines[i++].split(' ')[0]);
  let sumUnprinted = 0;
  const unprinted = lines[i++].split(' ').slice(1).map(Number);
  for(let i=0;i<F;i++) sumUnprinted += unprinted[i];
  const T = parseInt(lines[i++]);
  const total = N*(N+1)/2;
  const printed = total - sumUnprinted;
  const L = N/2;
  const expected = printed * (1 - T/L);
  results.push(expected.toFixed(4));
}
console.log(results.join('\n'));

